if (inputs.blockedPopulation <= 0 || inputs.toolAdoptionRate < 0 || inputs.toolAdoptionRate > 100 || inputs.contentAvailabilityImprovement < 0 || inputs.contentAvailabilityImprovement > 100 || inputs.connectionReliabilityScore < 1 || inputs.connectionReliabilityScore > 5 || inputs.speedImpactFactor < 0 || inputs.speedImpactFactor > 100 || inputs.securityPrivacyRating < 1 || inputs.securityPrivacyRating > 5 || inputs.usabilityEaseScore < 1 || inputs.usabilityEaseScore > 5 || inputs.evasionCapabilityScore < 1 || inputs.evasionCapabilityScore > 5) {
    return {
        accessImpactScore: 0,
        effectiveUserReach: 0,
        contentAccessibilityMetric: 0
    };
}

// Step 1: Calculate Effective User Reach
const effectiveUserReach = inputs.blockedPopulation * (inputs.toolAdoptionRate / 100);

// Step 2: Calculate Tool Performance Factor
const reliabilityFactor = inputs.connectionReliabilityScore / 5;
const speedFactor = (100 - inputs.speedImpactFactor) / 100; // 1 for no impact, 0 for 100% impact
const securityFactor = inputs.securityPrivacyRating / 5;
const usabilityFactor = inputs.usabilityEaseScore / 5;
const evasionFactor = inputs.evasionCapabilityScore / 5;

// Averaging the normalized performance factors
const toolPerformanceFactor = (reliabilityFactor + speedFactor + securityFactor + usabilityFactor + evasionFactor) / 5;

// Ensure toolPerformanceFactor is within a valid range [0, 1]
const clampedToolPerformanceFactor = Math.min(1, Math.max(0, toolPerformanceFactor));

// Step 3: Calculate Effective Content Accessibility Metric
// This adjusts the stated content availability improvement by the tool's actual performance quality
const contentAccessibilityMetric = inputs.contentAvailabilityImprovement * clampedToolPerformanceFactor;
// Ensure the metric is capped between 0 and 100
const clampedContentAccessibilityMetric = Math.min(100, Math.max(0, contentAccessibilityMetric));

// Step 4: Calculate Internet Freedom Access Impact Score
let accessImpactScore = 0;
if (inputs.blockedPopulation > 0) {
    const reachProportion = effectiveUserReach / inputs.blockedPopulation;
    // The score is the proportion of reached users multiplied by the effective content accessibility (as a fraction)
    accessImpactScore = reachProportion * (clampedContentAccessibilityMetric / 100) * 100;
}

// Ensure final score is capped between 0 and 100
const finalAccessImpactScore = Math.min(100, Math.max(0, accessImpactScore));

return {
    accessImpactScore: finalAccessImpactScore,
    effectiveUserReach: Math.round(effectiveUserReach),
    contentAccessibilityMetric: clampedContentAccessibilityMetric
};
